package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Iterator;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;
  private JsonArray jsonArray;

  @BeforeEach
  void setUp() throws Exception {
    jsonArray = new JsonArray();
    jsonArray.add("element1");
    jsonArray.add("element2");
    jsonTreeReader = new JsonTreeReader(jsonArray);

    // Set stack and stackSize manually to simulate internal state before beginArray
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = jsonArray;
    stackField.set(jsonTreeReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndicesField.set(jsonTreeReader, pathIndices);
  }

  @Test
  void beginArray_success_pushesIteratorAndSetsIndex() throws Exception {
    JsonTreeReader spyReader = spy(jsonTreeReader);

    // Use reflection to stub private expect(JsonToken) method to do nothing
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Replace private expect method in spyReader with a no-op using reflection and Mockito
    doAnswer(invocation -> null).when(spyReader).getClass()
        .getDeclaredMethod("expect", JsonToken.class)
        .invoke(spyReader, JsonToken.BEGIN_ARRAY);

    // Instead of above (which cannot work), use reflection to replace the private method via spy and doAnswer on a method handle
    // Since direct mocking of private method with Mockito is not possible, use doAnswer on the spy's expect method via reflection:
    // Use Mockito's doAnswer on spyReader but via reflection invoke expect, so we create a wrapper method for expect:
    // But since mocking private method is not possible directly, use a workaround: create a subclass to override expect or use a spy and reflection to set a flag.
    // Here, we will use reflection to set a flag to skip expect, or use reflection to call beginArray directly after temporarily making expect accessible and no-op.

    // Instead, invoke beginArray with expect temporarily replaced by a no-op via reflection:
    // Create a proxy to replace expect method temporarily
    // Use reflection to invoke beginArray but bypass expect by setting a flag or by temporarily replacing expect method via reflection.

    // Workaround: Use reflection to invoke expect and do nothing, then invoke beginArray after replacing expect with a no-op via reflection:

    // Temporarily replace expect with a no-op using reflection and MethodHandles (Java 9+), or use a subclass to override expect:

    // Create a subclass of JsonTreeReader that overrides expect to do nothing
    class JsonTreeReaderNoExpect extends JsonTreeReader {
      JsonTreeReaderNoExpect(JsonArray array) {
        super(array);
      }

      @Override
      protected void expect(JsonToken expected) {
        // no-op
      }
    }

    JsonTreeReaderNoExpect readerNoExpect = new JsonTreeReaderNoExpect(jsonArray);

    // Set internal fields as in setUp
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = jsonArray;
    stackField.set(readerNoExpect, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(readerNoExpect, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndicesField.set(readerNoExpect, pathIndices);

    // Use reflection to invoke private peekStack()
    Method peekStackMethod = JsonTreeReader.class.getDeclaredMethod("peekStack");
    peekStackMethod.setAccessible(true);
    Object top = peekStackMethod.invoke(readerNoExpect);
    assertSame(jsonArray, top);

    // Call beginArray
    readerNoExpect.beginArray();

    // Verify stackSize incremented
    int stackSize = stackSizeField.getInt(readerNoExpect);
    assertEquals(2, stackSize);

    // Verify top of stack is iterator of jsonArray
    stack = (Object[]) stackField.get(readerNoExpect);
    assertNotNull(stack[1]);
    assertTrue(stack[1] instanceof Iterator);

    // Verify pathIndices[stackSize - 1] == 0
    pathIndices = (int[]) pathIndicesField.get(readerNoExpect);
    assertEquals(0, pathIndices[stackSize - 1]);
  }

  @Test
  void beginArray_expectThrows_throwsIOException() throws Exception {
    // Create a subclass of JsonTreeReader that overrides expect to throw IOException
    class JsonTreeReaderExpectThrows extends JsonTreeReader {
      JsonTreeReaderExpectThrows(JsonArray array) {
        super(array);
      }

      @Override
      protected void expect(JsonToken expected) throws IOException {
        throw new IOException("expected exception");
      }
    }

    JsonTreeReaderExpectThrows readerExpectThrows = new JsonTreeReaderExpectThrows(jsonArray);

    // Set internal fields as in setUp
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = jsonArray;
    stackField.set(readerExpectThrows, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(readerExpectThrows, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndicesField.set(readerExpectThrows, pathIndices);

    IOException thrown = assertThrows(IOException.class, readerExpectThrows::beginArray);
    assertEquals("expected exception", thrown.getMessage());
  }
}

